func normalizeSQL(sql string) string {
	var b strings.Builder
	inString := false
	var quote rune
	spacePending := false

	runes := []rune(strings.TrimSpace(sql))
	for i := 0; i < len(runes); i++ {
		r := runes[i]
		if inString {
			b.WriteRune(r)
			if r == '\\' && i+1 < len(runes) {
				i++
				b.WriteRune(runes[i])
				continue
			}
			if r == quote {
				if i+1 < len(runes) && runes[i+1] == quote && quote != rune(0x60) {
					i++
					b.WriteRune(runes[i])
					continue
				}
				inString = false
			}
			continue
		}

		switch r {
		case '\'', '"', rune(0x60):
			if spacePending && b.Len() > 0 {
				b.WriteByte(' ')
				spacePending = false
			}
			inString = true
			quote = r
			b.WriteRune(r)
		case ' ', '\t', '\n', '\r':
			spacePending = b.Len() > 0
		default:
			if spacePending && b.Len() > 0 {
				b.WriteByte(' ')
				spacePending = false
			}
			b.WriteRune(r)
		}
	}

	return b.String()
}

